/**
 * @summary Submit a general enquiry or online session request
 */
export const getCreateEnquiryUrl = () => {
  return `/api/enquiries`;
};

export const createEnquiry = async (
  createEnquiryBody: CreateEnquiryBody,
  options?: RequestInit,
): Promise<Enquiry> => {
  return customFetch<Enquiry>(getCreateEnquiryUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createEnquiryBody),
  });
};

export const getCreateEnquiryMutationOptions = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createEnquiry>>,
    TError,
    { data: BodyType<CreateEnquiryBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createEnquiry>>,
  TError,
  { data: BodyType<CreateEnquiryBody> },
  TContext
> => {
  const mutationKey = ["createEnquiry"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createEnquiry>>,
    { data: BodyType<CreateEnquiryBody> }
  > = (props) => {
    const { data } = props ?? {};

    return createEnquiry(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type CreateEnquiryMutationResult = NonNullable<
  Awaited<ReturnType<typeof createEnquiry>>
>;
export type CreateEnquiryMutationBody = BodyType<CreateEnquiryBody>;
export type CreateEnquiryMutationError = ErrorType<void>;

/**
 * @summary Submit a general enquiry or online session request
 */
export const useCreateEnquiry = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createEnquiry>>,
    TError,
    { data: BodyType<CreateEnquiryBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof createEnquiry>>,
  TError,
  { data: BodyType<CreateEnquiryBody> },
  TContext
> => {
  return useMutation(getCreateEnquiryMutationOptions(options));
};
